"use client";

import * as React from "react";
import * as RechartsPrimitive from "recharts";

import { cn } from "@/lib/utils";

// Format: { THEME_NAME: CSS_SELECTOR }
const THEMES = { light: "", dark: ".dark" } as const;

export type ChartConfig = {
  [k in string]: {
    label?: React.ReactNode;
    icon?: React.ComponentType;
  } & (
    | { color?: string; theme?: never }
    | { color?: never; theme: Record<keyof typeof THEMES, string> }
  );
};

type ChartContextProps = {
  config: ChartConfig;
};

const ChartContext = React.createContext<ChartContextProps | null>(null);

function useChart() {
  const context = React.useContext(ChartContext);

  if (!context) {
    throw new Error("useChart must be used within a <ChartContainer />");
  }

  return context;
}

function ChartContainer({
  id,
  className,
  children,
  config,
  ...props
}: React.ComponentProps<"div"> & {
  config: ChartConfig;
  children: React.ComponentProps<
    typeof RechartsPrimitive.ResponsiveContainer
  >["children"];
}) {
  const uniqueId = React.useId();
  const chartId = `chart-${id || uniqueId.replace(/:/g, "")}`;

  return (
    <ChartContext.Provider value={{ config }}>
      <div
        data-slot="chart"
        data-chart={chartId}
        className={cn(
          "[&_.recharts-cartesian-axis-tick_text]:fill-muted-foreground [&_.recharts-cartesian-grid_line[stroke='#ccc']]:stroke-border/50 [&_.recharts-curve.recharts-tooltip-cursor]:stroke-border [&_.recharts-polar-grid_[stroke='#ccc']]:stroke-border [&_.recharts-radial-bar-background-sector]:fill-muted [&_.recharts-rectangle.recharts-tooltip-cursor]:fill-muted [&_.recharts-reference-line_[stroke='#ccc']]:stroke-border flex aspect-video justify-center text-xs [&_.recharts-dot[stroke='#fff']]:stroke-transparent [&_.recharts-layer]:outline-hidden [&_.recharts-sector]:outline-hidden [&_.recharts-sector[stroke='#fff']]:stroke-transparent [&_.recharts-surface]:outline-hidden",
          className,
        )}
        {...props}
      >
        <ChartStyle id={chartId} config={config} />
        <RechartsPrimitive.ResponsiveContainer width="100%" height="100%">
          {children}
        </RechartsPrimitive.ResponsiveContainer>
      </div>
    </ChartContext.Provider>
  );
}

const ChartStyle = ({ id, config }: { id: string; config: ChartConfig }) => {
  const colorConfig = Object.entries(config).filter(
    ([, c]) => c.theme || c.color,
  );

  if (!colorConfig.length) {
    return null;
  }

  return (
    <style
      // Scoped <style> for per-chart color variables (static config, not user input).
      dangerouslySetInnerHTML={{
        __html: Object.entries(THEMES)
          .map(
            ([theme, prefix]) => `
${prefix} [data-chart=${id}] {
${colorConfig
  .map(([key, itemConfig]) => {
    const color =
      itemConfig.theme?.[theme as keyof typeof itemConfig.theme] ||
      itemConfig.color;
    return color ? `  --color-${key}: ${color};` : null;
  })
  .join("\n")}
}
`,
          )
          .join("\n"),
      }}
    />
  );
};

const ChartTooltip = RechartsPrimitive.Tooltip;

/**
 * Inverted ("contrary to theme") chart-tooltip surface — ported 1:1 from the
 * Timbal Platform analytics tooltip: a dark card on a light page and a light
 * card on a dark page, soft floating shadow, `rounded-xl`, tight `px-5 py-4`
 * padding and an 11px base type scale.
 */
const CHART_TOOLTIP_SURFACE =
  "rounded-xl border px-5 py-4 text-left text-[11px] leading-snug shadow-[0_12px_40px_-10px_rgba(0,0,0,0.55)] border-white/10 bg-gradient-to-b from-neutral-800 to-neutral-950 text-white dark:border-black/10 dark:from-white dark:to-neutral-100 dark:text-neutral-900";
/** Primary text / values (white on dark, near-black on light). */
const CHART_TOOLTIP_TEXT = "text-white dark:text-neutral-900";
/** Row names / labels. */
const CHART_TOOLTIP_MUTED = "text-neutral-300 dark:text-neutral-600";

/**
 * A value usable as a CSS color for a legend/tooltip swatch. Recharts often
 * reports the series `fill` here, which in our charts is an SVG gradient
 * reference (`url(#…)`) — invalid for `background-color`, so we reject it and
 * fall back to the ChartConfig color / `--color-*` chain.
 */
function isCssColor(value: unknown): value is string {
  return (
    typeof value === "string" && value.length > 0 && !value.startsWith("url(")
  );
}

/**
 * Resolve the config lookup key from a legend/tooltip row. When `nameKey` is
 * passed (e.g. `"name"`), `key` is the field name — read the slice/category
 * value from the row or its nested `payload`, then fall back to `value`.
 */
function resolvePayloadConfigKey(
  payload: unknown,
  key: string,
): string {
  if (typeof payload !== "object" || payload === null) {
    return key;
  }

  const row = payload as Record<string, unknown>;
  const nested =
    "payload" in row &&
    typeof row.payload === "object" &&
    row.payload !== null
      ? (row.payload as Record<string, unknown>)
      : undefined;

  if (key in row && typeof row[key] === "string") {
    return row[key] as string;
  }
  if (nested && key in nested && typeof nested[key] === "string") {
    return nested[key] as string;
  }
  if (typeof row.value === "string") {
    return row.value;
  }

  return key;
}

/**
 * Resolve the swatch color for a legend/tooltip row: first usable payload
 * color, then the ChartConfig color, then the scoped `--color-{key}` variable
 * emitted by `ChartStyle`.
 */
function resolveSwatchColor(
  itemConfig: { color?: string } | undefined,
  configKey: string,
  ...candidates: unknown[]
): string {
  for (const candidate of candidates) {
    if (isCssColor(candidate)) return candidate;
  }
  if (isCssColor(itemConfig?.color)) return itemConfig.color as string;
  return `var(--color-${configKey})`;
}

type TooltipPayloadItem = {
  type?: string;
  value?: unknown;
  name?: string | number;
  dataKey?: string | number;
  color?: string;
  payload?: Record<string, unknown> & { fill?: string };
};

function ChartTooltipContent({
  active,
  payload,
  className,
  indicator = "dot",
  hideLabel = false,
  hideIndicator = false,
  label,
  labelFormatter,
  labelClassName,
  formatter,
  valueFormatter,
  color,
  nameKey,
  labelKey,
}: {
  active?: boolean;
  payload?: TooltipPayloadItem[];
  className?: string;
  indicator?: "line" | "dot" | "dashed";
  hideLabel?: boolean;
  hideIndicator?: boolean;
  label?: unknown;
  labelFormatter?: (value: unknown, payload: TooltipPayloadItem[]) => React.ReactNode;
  labelClassName?: string;
  formatter?: (
    value: unknown,
    name: string | number | undefined,
    item: TooltipPayloadItem,
    index: number,
    payload: unknown,
  ) => React.ReactNode;
  /**
   * Format only the value cell while keeping the default row (label + color
   * swatch). Prefer this over `formatter` when you just need custom number
   * formatting — `formatter` replaces the whole row, dropping the swatch.
   */
  valueFormatter?: (value: unknown, item: TooltipPayloadItem) => React.ReactNode;
  color?: string;
  nameKey?: string;
  labelKey?: string;
}) {
  const { config } = useChart();

  const tooltipLabel = React.useMemo(() => {
    if (hideLabel || !payload?.length) {
      return null;
    }

    const [item] = payload;
    const key = `${labelKey || item?.dataKey || item?.name || "value"}`;
    const itemConfig = getPayloadConfigFromPayload(config, item, key);
    const value =
      !labelKey && typeof label === "string"
        ? config[label]?.label || label
        : itemConfig?.label;

    if (labelFormatter) {
      return (
        <div className={cn("font-medium leading-none", labelClassName)}>
          {labelFormatter(value, payload)}
        </div>
      );
    }

    if (!value) {
      return null;
    }

    return (
      <div className={cn("font-medium leading-none", labelClassName)}>{value}</div>
    );
  }, [label, labelFormatter, payload, hideLabel, labelClassName, config, labelKey]);

  if (!active || !payload?.length) {
    return null;
  }

  const nestLabel = payload.length === 1 && indicator !== "dot";

  return (
    <div
      className={cn(
        "grid min-w-[8rem] items-start gap-1.5",
        CHART_TOOLTIP_SURFACE,
        "animate-in fade-in-0 zoom-in-95 duration-150",
        className,
      )}
    >
      {!nestLabel ? tooltipLabel : null}
      <div className="grid gap-1.5">
        {payload
          .filter((item) => item.type !== "none")
          .map((item, index) => {
            const key = `${nameKey || item.name || item.dataKey || "value"}`;
            const configKey = resolvePayloadConfigKey(item, key);
            const itemConfig = getPayloadConfigFromPayload(config, item, key);
            const indicatorColor = resolveSwatchColor(
              itemConfig,
              configKey,
              color,
              item.payload?.fill,
              item.color,
            );

            return (
              <div
                key={`${item.dataKey ?? index}`}
                className={cn(
                  "flex w-full flex-wrap items-stretch gap-2 [&>svg]:h-2.5 [&>svg]:w-2.5 [&>svg]:text-neutral-500 dark:[&>svg]:text-neutral-400",
                  indicator === "dot" && "items-center",
                )}
              >
                {formatter && item?.value !== undefined && item.name ? (
                  formatter(item.value, item.name, item, index, item.payload)
                ) : (
                  <>
                    {itemConfig?.icon ? (
                      <itemConfig.icon />
                    ) : (
                      !hideIndicator && (
                        <div
                          className={cn("shrink-0 rounded-[2px]", {
                            "h-2.5 w-2.5": indicator === "dot",
                            "w-1": indicator === "line",
                            "w-0 border-[1.5px] border-dashed bg-transparent":
                              indicator === "dashed",
                            "my-0.5": nestLabel && indicator === "dashed",
                          })}
                          style={{
                            backgroundColor:
                              indicator === "dashed" ? undefined : indicatorColor,
                            borderColor: indicatorColor,
                          }}
                        />
                      )
                    )}
                    <div
                      className={cn(
                        "flex flex-1 justify-between gap-3 leading-none",
                        nestLabel ? "items-end" : "items-center",
                      )}
                    >
                      <div className="grid gap-1.5">
                        {nestLabel ? tooltipLabel : null}
                        <span className={CHART_TOOLTIP_MUTED}>
                          {itemConfig?.label || item.name}
                        </span>
                      </div>
                      {item.value != null && (
                        <span className={cn("font-medium tabular-nums", CHART_TOOLTIP_TEXT)}>
                          {valueFormatter
                            ? valueFormatter(item.value, item)
                            : typeof item.value === "number"
                              ? item.value.toLocaleString()
                              : String(item.value)}
                        </span>
                      )}
                    </div>
                  </>
                )}
              </div>
            );
          })}
      </div>
    </div>
  );
}

const ChartLegend = RechartsPrimitive.Legend;

type LegendPayloadItem = {
  value?: unknown;
  type?: string;
  color?: string;
  dataKey?: string | number;
};

function ChartLegendContent({
  className,
  hideIcon = false,
  payload,
  verticalAlign = "bottom",
  nameKey,
}: {
  className?: string;
  hideIcon?: boolean;
  payload?: LegendPayloadItem[];
  verticalAlign?: "top" | "bottom";
  nameKey?: string;
}) {
  const { config } = useChart();

  if (!payload?.length) {
    return null;
  }

  return (
    <div
      className={cn(
        "flex items-center justify-center gap-4",
        verticalAlign === "top" ? "pb-3" : "pt-3",
        className,
      )}
    >
      {payload
        .filter((item) => item.type !== "none")
        .map((item, index) => {
          const key = `${nameKey || item.dataKey || "value"}`;
          const configKey = resolvePayloadConfigKey(item, key);
          const itemConfig = getPayloadConfigFromPayload(config, item, key);
          const swatchColor = resolveSwatchColor(itemConfig, configKey, item.color);

          return (
            <div
              key={`${item.value ?? index}`}
              className="[&>svg]:text-muted-foreground flex min-w-0 max-w-[8rem] items-center gap-1.5 [&>svg]:h-3 [&>svg]:w-3"
            >
              {itemConfig?.icon && !hideIcon ? (
                <itemConfig.icon />
              ) : (
                <div
                  className="h-2 w-2 shrink-0 rounded-[2px]"
                  style={{ backgroundColor: swatchColor }}
                />
              )}
              <span className="min-w-0 truncate">
                {itemConfig?.label ??
                  (item.value != null ? String(item.value) : null)}
              </span>
            </div>
          );
        })}
    </div>
  );
}

// Helper to extract item config from a payload.
function getPayloadConfigFromPayload(
  config: ChartConfig,
  payload: unknown,
  key: string,
) {
  if (typeof payload !== "object" || payload === null) {
    return undefined;
  }

  const configLabelKey = resolvePayloadConfigKey(payload, key);

  return configLabelKey in config
    ? config[configLabelKey]
    : config[key as keyof typeof config];
}

export {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
  ChartStyle,
  useChart,
};
